public struct SyncResult {
    public var detectedCreates: Int64
    public var detectedRenames: Int64
    public var detectedDeletes: Int64
    public var detectedModifies: Int64
    public var errors: [String]

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(detectedCreates: Int64, detectedRenames: Int64, detectedDeletes: Int64, detectedModifies: Int64, errors: [String]) {
        self.detectedCreates = detectedCreates
        self.detectedRenames = detectedRenames
        self.detectedDeletes = detectedDeletes
        self.detectedModifies = detectedModifies
        self.errors = errors
    }
}



extension SyncResult: Equatable, Hashable {
    public static func ==(lhs: SyncResult, rhs: SyncResult) -> Bool {
        if lhs.detectedCreates != rhs.detectedCreates {
            return false
        }
        if lhs.detectedRenames != rhs.detectedRenames {
            return false
        }
        if lhs.detectedDeletes != rhs.detectedDeletes {
            return false
        }
        if lhs.detectedModifies != rhs.detectedModifies {
            return false
        }
        if lhs.errors != rhs.errors {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(detectedCreates)
        hasher.combine(detectedRenames)
        hasher.combine(detectedDeletes)
        hasher.combine(detectedModifies)
        hasher.combine(errors)
    }
}


